            onnxParams.Learnables.onnx__Conv_192 = this.onnx__Conv_192;
            onnxParams.Learnables.onnx__Conv_193 = this.onnx__Conv_193;
            [x_blocks_2_depthwise, x_blocks_2_depthwiseNumDims] = ConvFcn(x_blocks_1_Add_outpu, x_blocks_1_Add_outpuNumDims, onnxParams, 'Training', false, ...
                'InputDataPermutation', {[2 1 3], ['as-is']}, ...
                'OutputDataPermutation', {[2 1 3], ['as-is']});
            if any(cellfun(@(A)~isnumeric(A) && ~islogical(A), {x_blocks_2_depthwise}))
                fprintf('Runtime error in network. At least one output of custom layer ''%s'' is a non-numeric, non-logical value.\n', 'ConvLayer1053');
                error(message('nnet_cnn_onnx:onnx:BadCustomLayerRuntimeOutput', 'ConvLayer1053'));
            end
            x_blocks_2_depthwise = dlarray(single(x_blocks_2_depthwise), 'CBT');
            if ~coder.target('MATLAB')
