        function [x_blocks_2_depthwise] = forward(this, x_blocks_1_Add_outpu)
            if isdlarray(x_blocks_1_Add_outpu)
                x_blocks_1_Add_outpu = stripdims(x_blocks_1_Add_outpu);
            end
            x_blocks_1_Add_outpuNumDims = 3;
            onnxParams = this.ONNXParams;
            onnxParams.Learnables.onnx__Conv_192 = this.onnx__Conv_192;
            onnxParams.Learnables.onnx__Conv_193 = this.onnx__Conv_193;
            [x_blocks_2_depthwise, x_blocks_2_depthwiseNumDims] = ConvFcn(x_blocks_1_Add_outpu, x_blocks_1_Add_outpuNumDims, onnxParams, 'Training', true, ...
