            if any(cellfun(@(A)~isnumeric(A) && ~islogical(A), {x_blocks_2_depthwise}))
                fprintf('Runtime error in network. At least one output of custom layer ''%s'' is a non-numeric, non-logical value.\n', 'ConvLayer1053');
                error(message('nnet_cnn_onnx:onnx:BadCustomLayerRuntimeOutput', 'ConvLayer1053'));
            end
            x_blocks_2_depthwise = dlarray(single(x_blocks_2_depthwise), 'CBT');
