function [inputDataPerms, outputDataPerms, Training] = parseInputs(x_blocks_1_Add_outpu, numDataOutputs, params, varargin)
% Function to validate inputs to ConvFcn:
p = inputParser;
isValidArrayInput = @(x)isnumeric(x) || isstring(x);
isValidONNXParameters = @(x)isa(x, 'ONNXParameters');
addRequired(p, 'x_blocks_1_Add_outpu', isValidArrayInput);
addRequired(p, 'params', isValidONNXParameters);
addParameter(p, 'InputDataPermutation', 'auto');
addParameter(p, 'OutputDataPermutation', 'auto');
addParameter(p, 'Training', false);
parse(p, x_blocks_1_Add_outpu, params, varargin{:});
inputDataPerms = p.Results.InputDataPermutation;
outputDataPerms = p.Results.OutputDataPermutation;
Training = p.Results.Training;
if isnumeric(inputDataPerms)
    inputDataPerms = {inputDataPerms};
end
if isstring(inputDataPerms) && isscalar(inputDataPerms) || ischar(inputDataPerms)
    inputDataPerms = repmat({inputDataPerms},1,1);
end
if isnumeric(outputDataPerms)
    outputDataPerms = {outputDataPerms};
end
if isstring(outputDataPerms) && isscalar(outputDataPerms) || ischar(outputDataPerms)
    outputDataPerms = repmat({outputDataPerms},1,numDataOutputs);
end
end

function [x_blocks_1_Add_outpu, Training, outputDataPerms, anyDlarrayInputs] = preprocessInput(x_blocks_1_Add_outpu, params, varargin)
% Parse input arguments
[inputDataPerms, outputDataPerms, Training] = parseInputs(x_blocks_1_Add_outpu, 1, params, varargin{:});
anyDlarrayInputs = any(cellfun(@(x)isa(x, 'dlarray'), {x_blocks_1_Add_outpu}));
% Make the input variables into unlabelled dlarrays:
x_blocks_1_Add_outpu = makeUnlabeledDlarray(x_blocks_1_Add_outpu);
% Permute inputs if requested:
x_blocks_1_Add_outpu = permuteInputVar(x_blocks_1_Add_outpu, inputDataPerms{1}, 3);
end

function [x_blocks_2_depthwise] = postprocessOutput(x_blocks_2_depthwise, outputDataPerms, anyDlarrayInputs, Training, varargin)
% Set output type:
